using System.Windows; using TestExpert.WPF.Data; using TestExpert.WPF.Services; using TestExpert.WPF.Views.Admin; using TestExpert.WPF.Views.Student; using TestExpert.WPF.Views.Teacher;
namespace TestExpert.WPF.Views;
public partial class LoginWindow : Window { public LoginWindow(){InitializeComponent();} private void BtnLogin_Click(object s,RoutedEventArgs e){ var u=new AuthService(new AppDbContext()).Login(TxtLogin.Text,PwdBox.Password); if(u==null){MessageBox.Show("Неверный логин или пароль.");return;} SessionManager.Login(u); Window n=u.Role.Name switch{"Admin"=>new AdminWindow(),"Teacher"=>new TeacherWindow(),"Student"=>new StudentWindow(),_=>throw new InvalidOperationException()}; n.Show(); Close(); } private void BtnRegister_Click(object s,RoutedEventArgs e)=>new RegisterWindow().ShowDialog(); }
